from fastmcp import FastMCP
import os
import subprocess
from typing import List

app = FastMCP(
    "quick-shell-tools",
    description="Simple MCP server exposing git_log and list_files via familiar shell commands."
)

def _expand_path(p: str) -> str:
    return os.path.abspath(os.path.expanduser(os.path.expandvars(p)))

def _run(cmd: List[str]) -> str:
    try:
        proc = subprocess.run(cmd, capture_output=True, text=True)
    except FileNotFoundError as e:
        return f"Error: {e}"
    out = proc.stdout or ""
    err = proc.stderr or ""
    if proc.returncode != 0:
        if out.strip():
            out += "\n"
        out += err if err.strip() else f"Command exited with code {proc.returncode}"
    return out if out.strip() else err

@app.tool()
def git_log(repo_path: str) -> str:
    """
    Show recent commits for a git repo.
    Runs: git -C <repo_path> --no-pager log --graph --decorate --oneline -n 20
    """
    path = _expand_path(repo_path)
    cmd = ["git", "-C", path, "--no-pager", "log", "--graph", "--decorate", "--oneline", "-n", "20"]
    return _run(cmd)

@app.tool()
def list_files(directory: str) -> str:
    """
    List files in a directory.
    Runs: ls -la <directory>
    """
    path = _expand_path(directory)
    cmd = ["ls", "-la", path]
    return _run(cmd)

if __name__ == "__main__":
    app.run()

