import asyncio
import json
import os
from typing import Any, Optional

from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp.types import Tool, TextContent

app = Server("env-reporter")


@app.list_tools()
async def list_tools() -> list[Tool]:
    return [
        Tool(
            name="report",
            description="Return a summary of environment variables (local-only; opt-in to include values).",
            inputSchema={
                "type": "object",
                "properties": {
                    "include_values": {
                        "type": "boolean",
                        "description": "If true, include variable values; otherwise only keys and count.",
                    },
                    "allowlist": {
                        "type": "array",
                        "items": {"type": "string"},
                        "description": "Optional list of variable names to include. If omitted, include all.",
                    },
                },
                "additionalProperties": False,
            },
        )
    ]


def collect_env(allowlist: Optional[list[str]], include_values: bool) -> dict:
    env = dict(os.environ)
    if allowlist:
        env = {k: v for k, v in env.items() if k in allowlist}
    if not include_values:
        return {"count": len(env), "keys": sorted(env.keys())}
    # Be careful: returning values may include secrets; only use with explicit consent.
    return env


@app.call_tool()
async def call_tool(name: str, arguments: Any | None):
    if name != "report":
        raise ValueError(f"Unknown tool: {name}")

    args = arguments or {}
    include_values = bool(args.get("include_values", False))
    allowlist = args.get("allowlist")
    if allowlist is not None and not isinstance(allowlist, list):
        raise ValueError("allowlist must be a list of strings")

    payload = collect_env(allowlist, include_values)
    return [TextContent(type="text", text=json.dumps(payload, indent=2, sort_keys=True))]


async def main():
    async with stdio_server() as (read_stream, write_stream):
        await app.run(read_stream, write_stream)


if __name__ == "__main__":
    asyncio.run(main())
