async def call_tool(name: str, arguments: dict[str, Any]) -> List[Content]:
    if name != "ask":
        raise ValueError(f"Unknown tool: {name}")

    q = arguments.get("q")
    if not isinstance(q, str) or not q.strip():
        raise ValueError("Argument 'q' must be a non-empty string")

    api_key = os.environ.get("OPENAI_API_KEY")
    if not api_key:
        raise RuntimeError("OPENAI_API_KEY is not set")

    async with httpx.AsyncClient(
        timeout=60,
        headers={"Authorization": f"Bearer {api_key}"}
    ) as http_client:
        client = AsyncOpenAI(api_key=api_key, http_client=http_client)

        resp = await client.chat.completions.create(
            model=MODEL,
            messages=[{"role": "user", "content": q}],
        )

    msg = resp.choices[0].message
    content = msg.content

    # Normalize content to a plain string
    if isinstance(content, str):
        text = content
    elif isinstance(content, list):
        # Concatenate any text parts
        parts = []
        for part in content:
            t = getattr(part, "text", None)
            if t:
                parts.append(t)
        text = "".join(parts)
    else:
        text = ""  # Fallback, should be rare

    return [TextContent(type="text", text=text)]


