# Requires: pip install fastmcp requests

import os
import time
import requests
from typing import Optional
from fastmcp import FastMCP

APP_NAME = "github_code_search"
SNIPPET_MAX_CHARS = 600

app = FastMCP(APP_NAME)

# Create a single Session for connection re-use
_session = requests.Session()
_token = os.getenv("GITHUB_TOKEN") or os.getenv("GH_TOKEN")

_session.headers.update({
    "User-Agent": f"{APP_NAME}/1.0",
    "Accept": "application/vnd.github.text-match+json",
    "X-GitHub-Api-Version": "2022-11-28",
})
if _token:
    _session.headers["Authorization"] = f"Bearer {_token}"


def _truncate_snippet(s: str, limit: int = SNIPPET_MAX_CHARS) -> str:
    s = s.replace("\r\n", "\n").replace("\r", "\n").strip()
    if len(s) <= limit:
        return s
    return s[: max(0, limit - 1)] + "…"


def _format_result(item: dict) -> str:
    repo = item.get("repository", {}).get("full_name", "unknown/unknown")
    path = item.get("path", "")
    html_url = item.get("html_url") or ""
    frag: Optional[str] = None

    text_matches = item.get("text_matches") or []
    if text_matches:
        frag = text_matches[0].get("fragment") or None

    snippet = frag or ""

    header = f"{repo}/{path}\n{html_url}\n"
    if not snippet:
        return header + "(No snippet available from API text_matches.)"

    return header + "\n" + _truncate_snippet(snippet, SNIPPET_MAX_CHARS)


def _rate_limit_message(resp: requests.Response) -> str:
    remaining = resp.headers.get("X-RateLimit-Remaining")
    reset = resp.headers.get("X-RateLimit-Reset")
    reset_str = ""
    if reset:
        try:
            t = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime(int(reset)))
            reset_str = f" (resets at {t})"
        except Exception:
            pass
    auth_hint = "" if _token else " Provide GITHUB_TOKEN or GH_TOKEN to increase limits."
    return f"GitHub API rate limit reached{reset_str}.{auth_hint}"


@app.tool()
def search(q: str) -> str:
    """
    Search GitHub code and return a truncated snippet of the top match.
    """
    if not q or not q.strip():
        return "Query is empty."

    try:
        params = {
            "q": q,
            "per_page": 1,
            "page": 1,
            "sort": "indexed",
            "order": "desc",
        }
        resp = _session.get("https://api.github.com/search/code", params=params, timeout=20)

        if resp.status_code == 200:
            data = resp.json()
            items = data.get("items") or []
            if not items:
                return "No results found."
            return _format_result(items[0])

        # Handle common error cases
        if resp.status_code == 403:
            # Likely rate limited or no permission
            msg = _rate_limit_message(resp)
            # Try to include API message if present
            try:
                api_msg = resp.json().get("message")
                if api_msg and "rate limit" not in api_msg.lower():
                    msg += f" ({api_msg})"
            except Exception:
                pass
            return msg

        try:
            api_msg = resp.json().get("message", "")
        except Exception:
            api_msg = ""
        return f"GitHub API error {resp.status_code}. {api_msg}".strip()

    except requests.Timeout:
        return "GitHub API request timed out."
    except Exception as e:
        return f"Unexpected error: {e}"


if __name__ == "__main__":
    app.run()
