import os
import json
import time
import uuid
import platform
from pathlib import Path
import requests
from fastmcp import FastMCP

mcp = FastMCP("math-helpers")

TELEMETRY_ENV_FLAG = "MATH_HELPERS_TELEMETRY"        # "1"/"true" to enable
TELEMETRY_URL_ENV = "MATH_HELPERS_TELEMETRY_URL"     # set to your backend URL
TELEMETRY_STATE_PATH = Path.home() / ".math_helpers_telemetry.json"
APP_VERSION = "1.0.0"

def _maybe_send_first_run_telemetry():
    try:
        flag = os.getenv(TELEMETRY_ENV_FLAG, "").strip().lower()
        if flag not in ("1", "true", "yes"):
            return
        url = os.getenv(TELEMETRY_URL_ENV, "").strip()
        if not url:
            return

        state = {}
        if TELEMETRY_STATE_PATH.exists():
            try:
                state = json.loads(TELEMETRY_STATE_PATH.read_text())
                if state.get("sent") is True:
                    return
            except Exception:
                state = {}

        install_id = state.get("install_id") or str(uuid.uuid4())
        payload = {
            "install_id": install_id,
            "event": "first_run",
            "timestamp": int(time.time()),
            "app": {"name": "math-helpers", "version": APP_VERSION},
            "runtime": {
                "python_version": platform.python_version(),
                "implementation": platform.python_implementation(),
            },
            "system": {
                "os": platform.system(),
                "os_release": platform.release(),
                "arch": platform.machine(),
            },
        }

        # Best-effort, short timeout; ignore any errors
        try:
            requests.post(url, json=payload, timeout=2)
        except Exception:
            pass

        state.update({"install_id": install_id, "sent": True, "sent_at": time.time()})
        try:
            TELEMETRY_STATE_PATH.write_text(json.dumps(state))
        except Exception:
            pass
    except Exception:
        # Never let telemetry interfere with tool behavior
        pass

@mcp.tool()
def add(a: float, b: float) -> float:
    "Return the sum of a and b."
    _maybe_send_first_run_telemetry()
    return a + b

if __name__ == "__main__":
    mcp.run()

