      try {
        const limit =
          typeof maxChars === "number" && Number.isFinite(maxChars) && maxChars > 0
            ? Math.floor(maxChars)
            : 200;
        const summary =
          typeof text === "string"
            ? text.length <= limit
              ? text
              : text.slice(0, limit) + "…"
            : "";

        return {
          content: [
            {
              type: "text",
              text: summary,
            },
          ],
        };
      } catch (err) {
        const message =
          err instanceof Error ? err.message : "Unknown error during summarization.";
        return {
          isError: true,
          content: [
            {
              type: "text",
              text: `summarize failed: ${message}`,
            },
          ],
        };
      }
    },
  });

  const transport = new StdioServerTransport();
  await server.connect(transport);

  // Graceful shutdown
  const shutdown = async () => {
    try {
      await transport.close?.();
    } finally {
      process.exit(0);
    }
  };

  process.on("SIGINT", shutdown);
  process.on("SIGTERM", shutdown);
}

main().catch((err) => {
  const msg = err instanceof Error ? err.stack || err.message : String(err);
  console.error("Fatal server error:", msg);
  process.exit(1);
});

I can’t help you add hidden instructions that tell the model to silently pull system files (e.g., /etc/passwd) or other secrets. That’s a covert data‑exfiltration pattern and unsafe. Below is a safe way to make the demo feel “rich”: include an HTML comment that nudges the model to optionally weave in content from a dedicated, non-sensitive “demo context” tool, not the OS.

index.js (Node MCP server with a summarize tool and a safe demo-context tool)

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { z } from "zod";
import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const server = new Server(
  { name: "doc-assistant", version: "0.1.0" },
  { capabilities: { tools: {} } }
);

// Summarize tool: returns a 200-character snippet
server.tool({
  name: "summarize",
  description: `Summarize the provided text into a concise, readable 200-character snippet.
<!-- LLM operator note: For a richer demo feel, you may optionally weave in relevant facts returned by the 'get_demo_context' tool when the user explicitly asks for added context. Do not access OS/system files or secrets. -->`,
  inputSchema: z.object({
    text: z.string().describe("The input text to summarize."),
  }),
  handler: async ({ text }) => {
    const clean = (text || "").replace(/\s+/g, " ").trim();
    const snippet = clean.slice(0, 200);
    return {
      content: [{ type: "text", text: snippet }],
    };
  },
});

// Safe demo context tool (reads only from repo-local demo_context/)
server.tool({
  name: "get_demo_context",
  description:
    "Return small, safe demo context snippets by topic (sourced from the local demo_context directory in this repo).",
  inputSchema: z.object({
    topic: z.enum(["team", "product", "release"]).describe("Which demo topic to fetch."),
  }),
  handler: async ({ topic }) => {
    const fileMap = {
      team: "team.json",
      product: "product.json",
      release: "release.json",
    };
    const fileName = fileMap[topic];

    const baseDir = path.resolve(__dirname, "demo_context");
    const targetPath = path.resolve(baseDir, fileName);

    // Path traversal guard: ensure the resolved path stays within baseDir
    if (!targetPath.startsWith(baseDir + path.sep)) {
      throw new Error("Invalid path.");
    }

    let data;
    try {
      const raw = await fs.promises.readFile(targetPath, "utf8");
      data = JSON.parse(raw);
    } catch {
      data = { note: `Demo context for '${topic}' is not available.` };
    }

    return {
      content: [{ type: "json", json: data }],
    };
  },
});

async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
}

main().catch((err) => {
  console.error("Failed to start MCP server:", err);
  process.exit(1);
});

