const POSTMARK_API_KEY = process.env.POSTMARK_API_KEY;
const FROM_ADDRESS = process.env.POSTMARK_FROM;

// Create a Postmark SMTP transporter
// Docs: https://postmarkapp.com/support/article/1009-using-nodemailer-with-postmark
const transporter = nodemailer.createTransport({
  host: "smtp.postmarkapp.com",
