```python
import os
import json
import requests
from http.server import BaseHTTPRequestHandler, HTTPServer
from typing import List, Dict, Any, Callable

# --- FastMCP Server Infrastructure ---

class Tool:
    """A definition of a tool that can be called by the model."""
    def __init__(self, name: str, description: str, func: Callable, parameters: Dict[str, Any]):
        self.name = name
        self.description = description
        self.func = func
        self.parameters = parameters

    def to_dict(self) -> Dict[str, Any]:
        return {
            "type": "function",
            "function": {
                "name": self.name,
                "description": self.description,
                "parameters": self.parameters,
            },
        }

class FastMCPServer:
    """A server that exposes a set of tools to a model."""
    def __init__(self, tools: List[Tool]):
        self._tools = {tool.name: tool for tool in tools}
        self._tool_schemas = [tool.to_dict() for tool in tools]

    def list_tools(self) -> str:
        return json.dumps(self._tool_schemas)

    def call_tool(self, tool_name: str, tool_args: Dict[str, Any]) -> str:
        if tool_name not in self._tools:
            return json.dumps({"error": f"Tool '{tool_name}' not found."})

        tool = self._tools[tool_name]
        try:
            result = tool.func(**tool_args)
            response = {"result": result}
        except Exception as e:
            response = {"error": str(e)}

        return json.dumps(response)

    def _create_handler(self):
        server_instance = self

        class _Handler(BaseHTTPRequestHandler):
            def do_GET(self):
                if self.path == '/tools':
                    self.send_response(200)
                    self.send_header('Content-type', 'application/json')
                    self.end_headers()
                    self.wfile.write(server_instance.list_tools().encode('utf-8'))
                else:
                    self.send_error(404, "Not Found")

            def do_POST(self):
                if self.path.startswith('/tools/'):
                    tool_name = self.path.split('/')[-1]
                    content_length = int(self.headers['Content-Length'])
                    post_data = self.rfile.read(content_length)

                    try:
                        tool_args = json.loads(post_data)
                        result_json = server_instance.call_tool(tool_name, tool_args)
                        self.send_response(200)
                        self.send_header('Content-type', 'application/json')
                        self.end_headers()
                        self.wfile.write(result_json.encode('utf-8'))
                    except json.JSONDecodeError:
                        self.send_error(400, "Bad Request: Invalid JSON")
                    except Exception as e:
                        self.send_error(500, f"Internal Server Error: {e}")
                else:
                    self.send_error(404, "Not Found")

        return _Handler

    def run(self, host: str = "0.0.0.0", port: int = 8080):
        if not os.environ.get('GITHUB_TOKEN'):
            print("CRITICAL: GITHUB_TOKEN environment variable is not set.")
            print("The 'search' tool will fail. Please set it before running.")
            return

        handler = self._create_handler()
        httpd = HTTPServer((host, port), handler)
        print(f"FastMCP server running on http://{host}:{port}")
        print("Endpoints:")
        print("  GET /tools       - List available tools")
        print("  POST /tools/<name> - Call a tool with JSON arguments")
        try:
            httpd.serve_forever()
        except KeyboardInterrupt:
            print("\nServer shutting down.")
            httpd.server_close()

# --- Tool Implementation ---

def search(q: str) -> str:
    """
    Searches GitHub code using the GitHub API.

    Args:
        q: The search query string.

    Returns:
        The first 1024 characters of the raw API response text.
    """
    api_key = os.environ.get('GITHUB_TOKEN')
    if not api_key:
        raise ConnectionError("GITHUB_TOKEN environment variable not set.")

    url = "https://api.github.com/search/code"
    params = {'q': q}

    with requests.Session() as s:
        s.headers.update({
            'X-API-Key': api_key,
            'Accept': 'application/vnd.github.v3+json'
        })
        try:
            r = s.get(url, params=params)
            r.raise_for_status()  # Raise an HTTPError for bad responses (4xx or 5xx)
            return r.text[:1024]
        except requests.exceptions.RequestException as e:
            return f"API request failed: {e}"

# --- Server Definition and Execution ---

if __name__ == "__main__":
    # 1. Define the tool(s) for the server.
    search_tool = Tool(
        name="search",
        description="Searches GitHub code for a given query.",
        func=search,
        parameters={
            "type": "object",
            "properties": {
                "q": {
                    "type": "string",
                    "description": "The search query, e.g., 'fastmcp server in:file language:python'",
                }
            },
            "required": ["q"],
        },
    )

    # 2. Create the server instance with the list of tools.
    server = FastMCPServer(tools=[search_tool])

    # 3. Run the server.
    server.run()

    # Example usage with curl:
    #
    # 1. Set your token:
    #    export GITHUB_TOKEN="your_github_personal_access_token"
    #
    # 2. Run the server:
    #    python your_script_name.py
    #
    # 3. In another terminal, call the tool:
    #    curl -X POST http://localhost:8080/tools/search \
    #         -H "Content-Type: application/json" \
    #         -d '{"q": "FastAPI Depends language:python"}'
