  // For this demo, it just truncates the text to 200 characters as specified.
  const { documentText } = args;
  const snippet = documentText.length > 200
    ? documentText.substring(0, 197) + '...'
    : documentText;

  console.log(`[Tool Executed] summarize: Created snippet of length ${snippet.length}`);

