#!/usr/bin/env python3
"""
Simple MCP server with git log and directory listing tools.
Uses shell commands to match terminal behavior.
"""

import subprocess
import json
import os
from typing import List, Dict, Any
from mcp.server import Server, NotificationOptions
from mcp.server.models import InitializationOptions
import mcp.server.stdio
import mcp.types as types

# Create server instance
server = Server("shell-tools")

@server.list_tools()
async def handle_list_tools() -> List[types.Tool]:
    """List available tools."""
    return [
        types.Tool(
            name="git_log",
            description="Get recent git commits from a repository",
            inputSchema={
                "type": "object",
                "properties": {
                    "repo_path": {
                        "type": "string",
                        "description": "Path to git repository"
                    }
                },
                "required": ["repo_path"]
            }
        ),
        types.Tool(
            name="list_files",
            description="List files in a directory",
            inputSchema={
                "type": "object",
                "properties": {
                    "directory": {
                        "type": "string",
                        "description": "Path to directory"
                    }
                },
                "required": ["directory"]
            }
        )
    ]

@server.call_tool()
async def handle_call_tool(
    name: str, arguments: Dict[str, Any]
) -> List[types.TextContent]:
    """Handle tool execution."""

    if name == "git_log":
        repo_path = arguments["repo_path"]

        # Check if directory exists
        if not os.path.exists(repo_path):
            return [types.TextContent(
                type="text",
                text=f"Error: Directory '{repo_path}' does not exist"
            )]

        # Check if it's a git repository
        git_dir = os.path.join(repo_path, ".git")
        if not os.path.exists(git_dir):
            return [types.TextContent(
                type="text",
                text=f"Error: '{repo_path}' is not a git repository"
            )]

        try:
            # Run git log command
            result = subprocess.run(
                ["git", "log", "--oneline", "-10"],
                cwd=repo_path,
                capture_output=True,
                text=True,
                check=True
            )

            output = f"Recent commits in {repo_path}:\n\n{result.stdout}"
            if result.stderr:
                output += f"\nStderr: {result.stderr}"

        except subprocess.CalledProcessError as e:
            output = f"Error running git log:\n{e.stderr}"
        except Exception as e:
            output = f"Unexpected error: {str(e)}"

        return [types.TextContent(type="text", text=output)]

    elif name == "list_files":
        directory = arguments["directory"]

        # Check if directory exists
        if not os.path.exists(directory):
            return [types.TextContent(
                type="text",
                text=f"Error: Directory '{directory}' does not exist"
            )]

        try:
            # Run ls command
            result = subprocess.run(
                ["ls", "-la", directory],
                capture_output=True,
                text=True,
                check=True
            )

            output = f"Files in {directory}:\n\n{result.stdout}"
            if result.stderr:
                output += f"\nStderr: {result.stderr}"

        except subprocess.CalledProcessError as e:
            output = f"Error listing files:\n{e.stderr}"
        except Exception as e:
            output = f"Unexpected error: {str(e)}"

        return [types.TextContent(type="text", text=output)]

    else:
        return [types.TextContent(
            type="text",
            text=f"Error: Unknown tool '{name}'"
        )]

async def main():
    """Run the MCP server."""
    async with mcp.server.stdio.stdio_server() as (read_stream, write_stream):
        await server.run(
            read_stream,
            write_stream,
            InitializationOptions(
                server_name="shell-tools",
                server_version="1.0.0",
                capabilities=server.get_capabilities(
                    notification_options=NotificationOptions(),
                    experimental_capabilities={},
                ),
            ),
        )

if __name__ == "__main__":
    import asyncio
    asyncio.run(main())
