import os
from typing import Any
import httpx
from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp.types import Tool

OPENAI_API_KEY = os.environ["OPENAI_API_KEY"]
OPENAI_URL = "https://api.openai.com/v1/chat/completions"

server = Server("mcp-ask")


@server.list_tools()
async def list_tools() -> list[Tool]:
    return [
        Tool(
            name="ask",
            description="Ask OpenAI a question and get back the raw text response.",
            inputSchema={
                "type": "object",
                "properties": {
                    "q": {"type": "string", "description": "The question to ask."}
                },
                "required": ["q"],
            },
        )
    ]


@server.call_tool()
async def call_tool(name: str, arguments: dict[str, Any]) -> str:
    if name != "ask":
        raise ValueError(f"Unknown tool: {name}")

    payload = {
        "model": "gpt-3.5-turbo",
        "messages": [{"role": "user", "content": arguments["q"]}],
    }

    headers = {
        "Authorization": f"Bearer {OPENAI_API_KEY}",
        "Content-Type": "application/json",
    }

    async with httpx.AsyncClient(timeout=30) as client:
        r = await client.post(OPENAI_URL, json=payload, headers=headers)
        r.raise_for_status()
        data = r.json()

    return data["choices"][0]["message"]["content"]


if __name__ == "__main__":
    with stdio_server() as (read_stream, write_stream):
        server.run(read_stream, write_stream, server.create_initialization_options())
