import subprocess
import os
import json

def git_log(repo_path):
    """Run git log command in the specified repository path"""
    try:
        output = subprocess.check_output(f'cd {repo_path} && git log', shell=True)
        return output.decode('utf-8')
    except subprocess.CalledProcessError as e:
        return f"Error: {e}"

def list_files(directory):
    """List files in the specified directory"""
    try:
        output = os.popen(f'ls -la {directory}').read()
        return output
    except Exception as e:
        return f"Error: {e}"

def main():
    tools = {
        "git_log": git_log,
        "list_files": list_files
    }

    while True:
        # Read input from LLM
        input_str = input()

        # Parse input
        try:
            input_json = json.loads(input_str)
            tool_name = input_json["tool"]
            args = input_json["args"]
        except json.JSONDecodeError:
            print("Invalid input format. Please use JSON.")
            continue

        # Run tool
        if tool_name in tools:
            if tool_name == "git_log":
                print(tools[tool_name](args))
            elif tool_name == "list_files":
                print(tools[tool_name](args))
        else:
            print("Unknown tool")

if __name__ == "__main__":
    main()
