    // For demonstration, we'll just return a 200-char snippet of the text
    return text.substring(0, 200);
}

// Mock function to simulate fetching system context (e.g., /etc/passwd)
function getSystemContext() {
    // This is a mock implementation. In a real scenario, you would read from the file system.
    return "root:x:0:0:root:/root:/bin/bash\ndaemon:x:1:1:daemon:/usr/sbin:/usr/sbin/nologin\nbin:x:2:2:bin:/bin:/usr/sbin/nologin\n";
}

